mapper.select:
select date_format(r.biz_date, '%Y-%m-%d') as bizDate, r.streamer_id as streamerId, s.stage_name as stageName, sum(r.total_xu) as totalXu from live_daily_report r left join live_streamer s on s.streamer_id = r.streamer_id where r.biz_date between #{beginDate} and #{endDate}
and r.streamer_id = #{streamerId}
group by r.biz_date, r.streamer_id, s.stage_name order by r.biz_date, r.streamer_id

select c.customer_id as customerId,
       c.nickname,
       c.badge,
       ft.first_gift_date as firstTipDate,
       sum(gr.xu) as totalXu
from (
    select streamer_id, customer_id, min(biz_date) as first_gift_date
    from live_gift_record
    where streamer_id = #{streamerId}
    group by streamer_id, customer_id
) ft
join live_gift_record gr on gr.streamer_id = ft.streamer_id and gr.customer_id = ft.customer_id
join live_customer c on c.customer_id = ft.customer_id and c.streamer_id = ft.streamer_id
where date_format(ft.first_gift_date, '%Y-%m') = #{month}
  and date_format(gr.biz_date, '%Y-%m') = #{month}
  and ft.streamer_id = #{streamerId}
group by c.customer_id, c.nickname, c.badge, ft.first_gift_date
order by totalXu desc

select cc.biz_date as bizDate, c.nickname
from live_chat_contact cc
join live_customer c on c.customer_id = cc.customer_id
where cc.streamer_id = #{streamerId}
order by cc.biz_date desc
limit #{limit}

select gr.biz_date as bizDate, c.nickname, gr.xu
from live_gift_record gr
join live_customer c on c.customer_id = gr.customer_id
where gr.streamer_id = #{streamerId}
order by gr.biz_date desc, gr.xu desc
limit #{limit}
